#include <stdio.h>
#include <string.h>

int main() {
    char strno[100];
    scanf("%s", strno);
    int n = strlen(strno);
    int sum1 = 0;
    for (int i = 1; i < n; i++) {
        sum1 += 1 << i;
    }
    for (int i = 0; i < n; i++) {
        if (strno[i] == '7') {
            sum1 += 1 << (n - i - 1);
        }
    }
    printf("%d\n", sum1 + 1);
    return 0;
}
